class Solution:
    def separateSquares(self, squares: List[List[int]]) -> float:
        def compute(y):
            above = below = 0.0
            for x, yi, s in squares:
                below += min(s, max(0, y - yi)) * s
                above += max(0, yi + s - y) * s
            return above - below
        lo, hi = min(s[1] for s in squares), max(s[1] + s[2] for s in squares)
        for _ in range(100):
            mid = (lo + hi) / 2
            if compute(mid) > 0:
                lo = mid
            else:
                hi = mid
        return (lo + hi) / 2

solution_js:
var separateSquares = function(squares) {
    function compute(y) {
        let above = 0, below = 0;
        for (const [x, yi, s] of squares) {
            below += Math.min(s, Math.max(0, y - yi)) * s;
            above += Math.max(0, yi + s - y) * s;
        }
        return above - below;
    }
    let lo = Math.min(...squares.map(s => s[1]));
    let hi = Math.max(...squares.map(s => s[1] + s[2]));
    for (let i = 0; i < 100; i++) {
        const mid = (lo + hi) / 2;
        if (compute(mid) > 0) lo = mid;
        else hi = mid;
    }
    return (lo + hi) / 2;
};

