class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        INF = float('inf')
        dist = [[INF] * 26 for _ in range(26)]
        for i in range(26): dist[i][i] = 0
        for o, c, w in zip(original, changed, cost):
            u, v = ord(o) - ord('a'), ord(c) - ord('a')
            dist[u][v] = min(dist[u][v], w)
        for k in range(26):
            for i in range(26):
                for j in range(26):
                    if dist[i][k] + dist[k][j] < dist[i][j]:
                        dist[i][j] = dist[i][k] + dist[k][j]
        ans = 0
        for s, t in zip(source, target):
            if s == t: continue
            c = dist[ord(s)-ord('a')][ord(t)-ord('a')]
            if c == INF: return -1
            ans += c
        return ans

solution_js:
var minimumCost = function(source, target, original, changed, cost) {
    const INF = Infinity;
    const dist = Array.from({length: 26}, (_, i) => Array.from({length: 26}, (_, j) => i === j ? 0 : INF));
    for (let i = 0; i < original.length; i++) {
        const u = original[i].charCodeAt(0) - 97;
        const v = changed[i].charCodeAt(0) - 97;
        dist[u][v] = Math.min(dist[u][v], cost[i]);
    }
    for (let k = 0; k < 26; k++)
        for (let i = 0; i < 26; i++)
            for (let j = 0; j < 26; j++)
                if (dist[i][k] + dist[k][j] < dist[i][j])
                    dist[i][j] = dist[i][k] + dist[k][j];
    let ans = 0;
    for (let i = 0; i < source.length; i++) {
        if (source[i] === target[i]) continue;
        const c = dist[source.charCodeAt(i) - 97][target.charCodeAt(i) - 97];
        if (c === INF) return -1;
        ans += c;
    }
    return ans;
};

