from math import comb
class Solution:
    def findNthSmallest(self, n: int, k: int) -> int:
        def count_le(x, k):
            bits = x.bit_length()
            total = 0
            ones = 0
            for i in range(bits - 1, -1, -1):
                if x & (1 << i):
                    total += comb(i, k - ones)
                    ones += 1
                    if ones > k: break
            if ones == k: total += 1
            return total
        lo, hi = 0, 10**18
        while lo < hi:
            mid = (lo + hi) // 2
            if count_le(mid, k) >= n:
                hi = mid
            else:
                lo = mid + 1
        return lo

solution_js:
var findNthSmallest = function(n, k) {
    function comb(n, r) {
        if (r < 0 || r > n) return 0n;
        if (r === 0 || r === n) return 1n;
        let num = 1n, den = 1n;
        for (let i = 0; i < r; i++) { num *= BigInt(n - i); den *= BigInt(i + 1); }
        return num / den;
    }
    function countLe(x, k) {
        const bits = x.toString(2).length;
        let total = 0n, ones = 0;
        for (let i = bits - 1; i >= 0; i--) {
            if ((x >> BigInt(i)) & 1n) {
                total += comb(i, k - ones);
                ones++;
                if (ones > k) break;
            }
        }
        if (ones === k) total += 1n;
        return total;
    }
    let lo = 0n, hi = BigInt(10 ** 18);
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        if (countLe(mid, k) >= BigInt(n)) hi = mid;
        else lo = mid + 1n;
    }
    return Number(lo);
};

