from collections import Counter
class Solution:
    def isTrionic(self, nums: List[int]) -> bool:
        freq = Counter(nums)
        if any(v % 3 != 0 for v in freq.values()):
            return False
        nums.sort()
        for i in range(0, len(nums), 3):
            if nums[i] != nums[i+1] or nums[i+1] != nums[i+2]:
                return False
        return True

