from collections import Counter
class Solution:
    def minOperations(self, nums: List[int]) -> int:
        n = len(nums)
        if n % 3 != 0:
            return -1
        total = 0
        for i in range(0, n, 3):
            group = nums[i:i+3]
            freq = Counter(group)
            max_freq = max(freq.values())
            total += 3 - max_freq
        return total

