var minOperations = function(nums) {
    const n = nums.length;
    if (n % 3 !== 0) return -1;
    let total = 0;
    for (let i = 0; i < n; i += 3) {
        const group = nums.slice(i, i + 3);
        const freq = new Map();
        for (const x of group) freq.set(x, (freq.get(x) || 0) + 1);
        const maxFreq = Math.max(...freq.values());
        total += 3 - maxFreq;
    }
    return total;
};

