class Solution:
    def smallestDivisor(self, nums: List[int], threshold: int) -> int:
        def compute(d):
            return sum((n + d - 1) // d for n in nums)
        lo, hi = 1, max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if compute(mid) <= threshold:
                hi = mid
            else:
                lo = mid + 1
        return lo

