class Solution:
    def numBusesToDestination(self, routes: List[List[int]], source: int, target: int) -> int:
        from collections import defaultdict, deque
        if source == target: return 0
        stop_to_routes = defaultdict(set)
        for i, route in enumerate(routes):
            for stop in route:
                stop_to_routes[stop].add(i)
        visited_routes = set()
        visited_stops = {source}
        queue = deque([(source, 0)])
        while queue:
            stop, buses = queue.popleft()
            for route_idx in stop_to_routes[stop]:
                if route_idx in visited_routes: continue
                visited_routes.add(route_idx)
                for next_stop in routes[route_idx]:
                    if next_stop == target: return buses + 1
                    if next_stop not in visited_stops:
                        visited_stops.add(next_stop)
                        queue.append((next_stop, buses + 1))
        return -1

solution_js:
var numBusesToDestination = function(routes, source, target) {
    if (source === target) return 0;
    const stopToRoutes = new Map();
    for (let i = 0; i < routes.length; i++)
        for (const stop of routes[i]) {
            if (!stopToRoutes.has(stop)) stopToRoutes.set(stop, new Set());
            stopToRoutes.get(stop).add(i);
        }
    const visitedRoutes = new Set(), visitedStops = new Set([source]);
    const queue = [[source, 0]];
    let qi = 0;
    while (qi < queue.length) {
        const [stop, buses] = queue[qi++];
        for (const ri of (stopToRoutes.get(stop) || [])) {
            if (visitedRoutes.has(ri)) continue;
            visitedRoutes.add(ri);
            for (const ns of routes[ri]) {
                if (ns === target) return buses + 1;
                if (!visitedStops.has(ns)) { visitedStops.add(ns); queue.push([ns, buses + 1]); }
            }
        }
    }
    return -1;
};

