class Solution:
    def maximumLength(self, nums: List[int]) -> int:
        n = len(nums)
        dp0 = dp1 = 1
        ans = 1
        for i in range(1, n):
            new_dp0 = dp0 + 1 if nums[i] >= nums[i-1] else 1
            new_dp1 = dp0 + 1  # replace nums[i] to fit
            if nums[i] >= nums[i-1]:
                new_dp1 = max(new_dp1, dp1 + 1)
            dp0, dp1 = new_dp0, new_dp1
            ans = max(ans, dp0, dp1)
        return ans

