class Solution:
    def sequenceReconstruction(self, nums: List[int], sequences: List[List[int]]) -> bool:
        from collections import defaultdict, deque
        n = len(nums)
        graph = defaultdict(set)
        indegree = defaultdict(int)
        nodes = set()
        for seq in sequences:
            for v in seq:
                if v < 1 or v > n: return False
                nodes.add(v)
            for i in range(len(seq) - 1):
                a, b = seq[i], seq[i+1]
                if b not in graph[a]:
                    graph[a].add(b)
                    indegree[b] += 1
        if nodes != set(nums): return False
        queue = deque([v for v in range(1, n+1) if indegree[v] == 0])
        order = []
        while queue:
            if len(queue) > 1: return False
            v = queue.popleft()
            order.append(v)
            for nb in graph[v]:
                indegree[nb] -= 1
                if indegree[nb] == 0: queue.append(nb)
        return order == nums

solution_js:
var sequenceReconstruction = function(nums, sequences) {
    const n = nums.length;
    const graph = new Map(), indegree = new Map();
    for (let i = 1; i <= n; i++) { graph.set(i, new Set()); indegree.set(i, 0); }
    for (const seq of sequences)
        for (let i = 0; i < seq.length - 1; i++) {
            const [a, b] = [seq[i], seq[i+1]];
            if (!graph.get(a).has(b)) { graph.get(a).add(b); indegree.set(b, indegree.get(b) + 1); }
        }
    const queue = [];
    for (let i = 1; i <= n; i++) if (indegree.get(i) === 0) queue.push(i);
    let qi = 0;
    const order = [];
    while (qi < queue.length) {
        if (queue.length - qi > 1) return false;
        const v = queue[qi++];
        order.push(v);
        for (const nb of graph.get(v)) {
            indegree.set(nb, indegree.get(nb) - 1);
            if (indegree.get(nb) === 0) queue.push(nb);
        }
    }
    return JSON.stringify(order) === JSON.stringify(nums);
};

var pathSum = function(root, targetSum) {
    const prefix = new Map([[0, 1]]);
    let ans = 0;
    function dfs(node, curr) {
        if (!node) return;
        curr += node.val;
        ans += (prefix.get(curr - targetSum) || 0);
        prefix.set(curr, (prefix.get(curr) || 0) + 1);
        dfs(node.left, curr);
        dfs(node.right, curr);
        prefix.set(curr, prefix.get(curr) - 1);
    }
    dfs(root, 0);
    return ans;
};

