class Solution:
    def maxStability(self, n: int, edges: list, k: int) -> int:
        def find(p, x):
            while p[x] != x: p[x] = p[p[x]]; x = p[x]
            return x
        def union(p, rank, x, y):
            rx, ry = find(p, x), find(p, y)
            if rx == ry: return False
            if rank[rx] < rank[ry]: rx, ry = ry, rx
            p[ry] = rx
            if rank[rx] == rank[ry]: rank[rx] += 1
            return True
