                        components -= 1
                else:
                    if upgrades_used < k:
                        if union(p, rank, u, v):
                            components -= 1
                            upgrades_used += 1
            return components == 1
        sorted_edges = sorted([(w, u, v) for u, v, w in edges], reverse=True)
        weights = sorted(set(w for u, v, w in edges))
        lo, hi = 0, len(weights) - 1
        ans = weights[0] if weights else 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(weights[mid]):
                ans = weights[mid]
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

