class Solution:
    def getHappyString(self, n: int, k: int) -> str:
        result = []

        def backtrack(s):
            if len(s) == n:
                result.append(s)
                return
            for c in ['a', 'b', 'c']:
                if not s or s[-1] != c:
                    backtrack(s + c)

        backtrack('')
        return result[k - 1] if k <= len(result) else ''

