class AutocompleteSystem {
    constructor(sentences, times) {
        this.trie = {};
        this.cur = '';
        this.node = this.trie;
        for (let i = 0; i < sentences.length; i++) {
            this._insert(sentences[i], times[i]);
        }
    }

    _insert(sentence, freq) {
        let node = this.trie;
        for (const c of sentence) {
            if (!node[c]) node[c] = {};
            node = node[c];
        }
        node['#'] = (node['#'] || 0) + freq;
    }

    _search(node, prefix) {
        const res = [];
        if (node['#']) res.push([node['#'], prefix]);
        for (const [c, child] of Object.entries(node)) {
            if (c !== '#') res.push(...this._search(child, prefix + c));
        }
        return res;
    }

    input(c) {
        if (c === '#') {
            this._insert(this.cur, 1);
            this.cur = '';
            this.node = this.trie;
            return [];
        }
        this.cur += c;
        if (!this.node || !this.node[c]) {
            this.node = null;
            return [];
        }
        this.node = this.node[c];
        const results = this._search(this.node, this.cur);
        results.sort((a, b) => b[0] - a[0] || a[1].localeCompare(b[1]));
        return results.slice(0, 3).map(x => x[1]);
    }
}

