class Solution:
    def maximumSubarraySum(self, nums: List[int], k: int) -> int:
        # k is not used here; problem is about |a-b| <= 1
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i+1] = prefix[i] + nums[i]

        min_prefix = {}  # value -> min prefix sum at index with that value
        ans = float('-inf')
        found = False

        for j in range(n):
            v = nums[j]
            for target in [v-1, v, v+1]:
                if target in min_prefix:
                    ans = max(ans, prefix[j+1] - min_prefix[target])
                    found = True
            # update map with prefix[j] for value nums[j]
            if v not in min_prefix or prefix[j] < min_prefix[v]:
                min_prefix[v] = prefix[j]

        return ans if found else 0

