class Solution:
    def flipAndCountOnes(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        total = sum(sum(row) for row in grid)
        best = total

        for r in range(m):
            for c in range(n):
                max_k = min(m - r, n - c)
                for k in range(1, max_k + 1):
                    # flip submatrix grid[r:r+k][c:c+k] vertically
                    # count change in 1s
                    delta = 0
                    for i in range(r, r + k):
                        for j in range(k // 2):
                            left = c + j
                            right = c + k - 1 - j
                            if grid[i][left] != grid[i][right]:
                                # after flip one becomes 0 and one becomes 1 (net 0 change)
                                pass
                            # no net change when symmetric positions differ
                            # delta only when same value at mirror positions
                        for j in range(k // 2):
                            left = c + j
                            right = c + k - 1 - j
                            # swapping doesnt change count
                            pass
                    best = max(best, total)
        return best

