        if (mountainArr.get(mid) < mountainArr.get(mid + 1)) lo = mid + 1;
        else hi = mid;
    }
    const peak = lo;
    // Search ascending
    lo = 0; hi = peak;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        const val = mountainArr.get(mid);
        if (val === target) return mid;
        else if (val < target) lo = mid + 1;
        else hi = mid - 1;
    }
    // Search descending
    lo = peak + 1; hi = n - 1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        const val = mountainArr.get(mid);
        if (val === target) return mid;
        else if (val > target) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1;
};

