    for (let i = 0; i < n; i++) {
        if (str1[i] === 'T') {
            for (let j = 0; j < m; j++) {
                if (forced[i+j] && result[i+j] !== str2[j]) return '';
                result[i+j] = str2[j];
                forced[i+j] = true;
            }
        }
