        if (str1[i] === 'F') {
            const match = Array.from({length: m}, (_, j) => result[i+j] === str2[j]).every(Boolean);
            if (match) {
                let changed = false;
                for (let j = m - 1; j >= 0; j--) {
                    if (!forced[i+j]) {
                        result[i+j] = str2[j] === 'a' ? 'b' : 'a';
                        changed = true;
                        break;
                    }
                }
                if (!changed) return '';
            }
