    def countSubmatrices(self, grid: list[list[int]], k: int) -> int:
        m, n = len(grid), len(grid[0])
        prefix = [[0] * n for _ in range(m)]
        count = 0
        for i in range(m):
            for j in range(n):
                prefix[i][j] = grid[i][j]
                if i > 0:
                    prefix[i][j] += prefix[i-1][j]
                if j > 0:
                    prefix[i][j] += prefix[i][j-1]
                if i > 0 and j > 0:
                    prefix[i][j] -= prefix[i-1][j-1]
                if prefix[i][j] <= k:
                    count += 1
        return count

