from collections import Counter

class Solution:
    def minOperations(self, nums: list[int]) -> int:
        n = len(nums)
        max_val = max(nums) if nums else 2
        limit = max(max_val, 3)
        sieve = [True] * (limit + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(limit**0.5) + 1):
            if sieve[i]:
                for j in range(i*i, limit + 1, i):
                    sieve[j] = False

        even_cnt = Counter()
        odd_cnt = Counter()
        for i, v in enumerate(nums):
            if i % 2 == 0:
                even_cnt[v] += 1
            else:
                odd_cnt[v] += 1

        even_primes = sorted([(cnt, v) for v, cnt in even_cnt.items() if v <= limit and sieve[v]], reverse=True)
        odd_primes = sorted([(cnt, v) for v, cnt in odd_cnt.items() if v <= limit and sieve[v]], reverse=True)

        if not even_primes:
            even_primes = [(0, 2)]
        if not odd_primes:
            odd_primes = [(0, 3)]

        best = float('inf')
        for i in range(min(2, len(even_primes))):
            for j in range(min(2, len(odd_primes))):
                ec, ev = even_primes[i]
                oc, ov = odd_primes[j]
                if ev != ov:
                    cost = n - ec - oc
                    best = min(best, cost)

        return best if best < float('inf') else n

