class Solution:
    def maxScore(self, nums: list[int], k: int) -> int:
        n = len(nums)
        arr = nums + nums
        m = 2 * n
        prefix = [0] * (m + 1)
        for i in range(m):
            prefix[i+1] = prefix[i] + arr[i]

        NEG_INF = float('-inf')
        prev = [NEG_INF] * (m + 1)
        prev[0] = 0

        for j in range(1, k + 1):
            curr = [NEG_INF] * (m + 1)
            running_max = NEG_INF
            for i in range(j, m + 1):
                if prev[i-1] != NEG_INF:
                    running_max = max(running_max, prev[i-1] - prefix[i-1])
                if running_max != NEG_INF:
                    curr[i] = running_max + prefix[i]
            prev = curr

        ans = prev[n]
        return max(0, ans) if ans != NEG_INF else 0

