    const arr = [...nums, ...nums];
    const m = 2 * n;
    const prefix = new Array(m + 1).fill(0);
    for (let i = 0; i < m; i++) prefix[i+1] = prefix[i] + arr[i];

    const NEG_INF = -Infinity;
    let prev = new Array(m + 1).fill(NEG_INF);
    prev[0] = 0;

    for (let j = 1; j <= k; j++) {
        const curr = new Array(m + 1).fill(NEG_INF);
        let runMax = NEG_INF;
        for (let i = j; i <= m; i++) {
            if (prev[i-1] !== NEG_INF) runMax = Math.max(runMax, prev[i-1] - prefix[i-1]);
            if (runMax !== NEG_INF) curr[i] = runMax + prefix[i];
        }
        prev = curr;
    }

    return prev[n] !== NEG_INF ? Math.max(0, prev[n]) : 0;
};

