class Solution:
    def findCoins(self, ways: list[int]) -> list[int]:
        n = len(ways)
        dp = [0] * (n + 1)
        dp[0] = 1
        coins = []

        for c in range(1, n + 1):
            expected = dp[c]
            if ways[c - 1] != expected:
                coins.append(c)
                for j in range(c, n + 1):
                    dp[j] += dp[j - c]

        for i in range(n):
            if dp[i + 1] != ways[i]:
                return []
        return coins

