class Solution:
    def minimizeHammingDistance(self, source: list[int], target: list[int], allowedSwaps: list[list[int]]) -> int:
        n = len(source)
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            parent[find(a)] = find(b)

        for a, b in allowedSwaps:
            union(a, b)

        groups = {}
        for i in range(n):
            r = find(i)
            if r not in groups:
                groups[r] = []
            groups[r].append(i)

        hamming = 0
        for indices in groups.values():
            src_cnt = Counter(source[i] for i in indices)
            tgt_cnt = Counter(target[i] for i in indices)
            matched = sum((src_cnt & tgt_cnt).values())
            hamming += len(indices) - matched

        return hamming

solution_js:
var minimizeHammingDistance = function(source, target, allowedSwaps) {
    const n = source.length;
    const parent = Array.from({length: n}, (_, i) => i);

    const find = (x) => {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    };

    for (const [a, b] of allowedSwaps) parent[find(a)] = find(b);

    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const r = find(i);
        if (!groups.has(r)) groups.set(r, []);
        groups.get(r).push(i);
    }

    let hamming = 0;
    for (const indices of groups.values()) {
        const srcCnt = new Map(), tgtCnt = new Map();
        for (const i of indices) {
            srcCnt.set(source[i], (srcCnt.get(source[i])||0)+1);
            tgtCnt.set(target[i], (tgtCnt.get(target[i])||0)+1);
        }
        let matched = 0;
        for (const [v, c] of srcCnt) matched += Math.min(c, tgtCnt.get(v)||0);
        hamming += indices.length - matched;
    }
    return hamming;
};

