var hasValidPath = function(grid) {
    const connects = {
        1: [[0,-1,1],[0,1,0]],
        2: [[-1,0,3],[1,0,2]],
        3: [[0,-1,1],[1,0,2]],
        4: [[0,1,0],[1,0,2]],
        5: [[0,-1,1],[-1,0,3]],
        6: [[0,1,0],[-1,0,3]],
    };
    const m = grid.length, n = grid[0].length;
    const visited = Array.from({length: m}, () => new Array(n).fill(false));
    const queue = [[0,0]];
    visited[0][0] = true;
    let qi = 0;
    while (qi < queue.length) {
        const [r, c] = queue[qi++];
        if (r === m-1 && c === n-1) return true;
        for (const [dr, dc] of connects[grid[r][c]]) {
            const nr = r+dr, nc = c+dc;
            if (nr>=0 && nr<m && nc>=0 && nc<n && !visited[nr][nc]) {
                const back = connects[grid[nr][nc]].some(([bdr,bdc]) => bdr===-dr && bdc===-dc);
                if (back) { visited[nr][nc]=true; queue.push([nr,nc]); }
            }
        }
    }
    return visited[m-1][n-1];
};

