class Solution:
    def applySubstitutions(self, replacements: list[list[str]], text: str) -> str:
        rules = {k: v for k, v in replacements}
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def expand(s):
            result = []
            i = 0
            while i < len(s):
                if s[i] == '%':
                    j = s.index('%', i + 1)
                    var = s[i+1:j]
                    result.append(expand(rules[var]))
                    i = j + 1
                else:
                    result.append(s[i])
                    i += 1
            return ''.join(result)

        return expand(text)

