var applySubstitutions = function(replacements, text) {
    const rules = new Map(replacements);
    const memo = new Map();

    function expand(s) {
        if (memo.has(s)) return memo.get(s);
        let result = '';
        let i = 0;
        while (i < s.length) {
            if (s[i] === '%') {
                const j = s.indexOf('%', i + 1);
                const varName = s.slice(i + 1, j);
                result += expand(rules.get(varName));
                i = j + 1;
            } else {
                result += s[i];
                i++;
            }
        }
        memo.set(s, result);
        return result;
    }

    return expand(text);
};

