class Solution:
    def maximumScore(self, grid: list[list[int]]) -> int:
        n = len(grid)
        m = len(grid[0])
        # prefix sums per column
        pre = [[0] * (n + 1) for _ in range(m)]
        for j in range(m):
            for i in range(n):
                pre[j][i + 1] = pre[j][i] + grid[i][j]
        # dp[r] = max score ending with r rows colored in previous column
        INF = float('-inf')
        dp = [0] * (n + 1)  # initially 0 rows colored, score 0
        for j in range(m - 1):
            ndp = [INF] * (n + 1)
            # best[r] for current col having r rows colored
            for cur in range(n + 1):
                for prev in range(n + 1):
                    if dp[prev] == INF:
                        continue
                    # score = cells in col j+1 colored by cur but not by prev
                    # i.e., rows [prev..cur-1] if cur > prev, else 0 from this transition
                    # Actually score comes from col j cells not overlapping with col j+1
                    # Redefine: score when transitioning from prev (col j rows) to cur (col j+1 rows)
                    # = sum of col j rows >= cur (they are only in col j)
                    score = pre[j][n] - pre[j][min(cur, n)]
                    if cur <= prev:
                        score = pre[j][prev] - pre[j][cur]
                    else:
                        score = 0
                    val = dp[prev] + score
                    if val > ndp[cur]:
                        ndp[cur] = val
            dp = ndp
        # last column contribution
        ans = 0
        for prev in range(n + 1):
            if dp[prev] != INF:
                ans = max(ans, dp[prev] + pre[m - 1][prev])
        return ans

