var maximumScore = function(grid) {
    const n = grid.length, m = grid[0].length;
    const pre = Array.from({length: m}, () => new Array(n + 1).fill(0));
    for (let j = 0; j < m; j++)
        for (let i = 0; i < n; i++)
            pre[j][i + 1] = pre[j][i] + grid[i][j];

    let dp = new Array(n + 1).fill(-Infinity);
    dp[0] = 0;
    for (let j = 0; j < m - 1; j++) {
        const ndp = new Array(n + 1).fill(-Infinity);
        for (let prev = 0; prev <= n; prev++) {
            if (dp[prev] === -Infinity) continue;
            for (let cur = 0; cur <= n; cur++) {
                const score = cur <= prev ? pre[j][prev] - pre[j][cur] : 0;
                const val = dp[prev] + score;
                if (val > ndp[cur]) ndp[cur] = val;
            }
        }
        dp = ndp;
    }
    let ans = 0;
    for (let prev = 0; prev <= n; prev++) {
        if (dp[prev] !== -Infinity)
            ans = Math.max(ans, dp[prev] + pre[m - 1][prev]);
    }
    return ans;
};

