from typing import List
import heapq

class Solution:
    def minCost(self, nums: List[int], costs: List[int]) -> int:
        n = len(nums)
        # Build adjacency using monotonic stacks
        graph = [[] for _ in range(n)]
        stack = []  # indices for nums[i] >= 0 jumps
        for i in range(n):
            while stack and nums[stack[-1]] < nums[i]:
                graph[stack[-1]].append(i)
                stack.pop()
            if stack:
                graph[stack[-1]].append(i)
            stack.append(i)
        stack = []  # indices for nums[i] < 0 jumps
        for i in range(n):
            while stack and nums[stack[-1]] > nums[i]:
                graph[stack[-1]].append(i)
                stack.pop()
            if stack:
                graph[stack[-1]].append(i)
            stack.append(i)
        # Dijkstra
        dist = [float('inf')] * n
        dist[0] = 0
        heap = [(0, 0)]
        while heap:
            d, u = heapq.heappop(heap)
            if d > dist[u]:
                continue
            for v in graph[u]:
                nd = d + costs[v]
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(heap, (nd, v))
        return dist[n-1]

