from collections import defaultdict, deque
from typing import List

class Solution:
    def minJumps(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return 0

        # Map prime -> list of indices
        prime_to_idx = defaultdict(list)
        for i, v in enumerate(nums):
            x = v
            d = 2
            while d * d <= x:
                if x % d == 0:
                    prime_to_idx[d].append(i)
                    while x % d == 0:
                        x //= d
                d += 1
            if x > 1:
                prime_to_idx[x].append(i)

        dist = [-1] * n
        dist[0] = 0
        q = deque([0])
        visited_primes = set()

        while q:
            idx = q.popleft()
            d = dist[idx]
            # Adjacent jumps
            for nxt in [idx - 1, idx + 1]:
                if 0 <= nxt < n and dist[nxt] == -1:
                    dist[nxt] = d + 1
                    if nxt == n - 1:
                        return dist[nxt]
                    q.append(nxt)
            # Prime teleportation
            x = nums[idx]
            f = 2
            primes = []
            while f * f <= x:
                if x % f == 0:
                    primes.append(f)
                    while x % f == 0:
                        x //= f
                f += 1
            if x > 1:
                primes.append(x)
            for p in primes:
                if p not in visited_primes:
                    visited_primes.add(p)
                    for nxt in prime_to_idx[p]:
                        if dist[nxt] == -1:
                            dist[nxt] = d + 1
                            if nxt == n - 1:
                                return dist[nxt]
                            q.append(nxt)
        return dist[n - 1]

solution_js:
var minJumps = function(nums) {
    const n = nums.length;
    if (n === 1) return 0;
    const primeToIdx = new Map();
    for (let i = 0; i < n; i++) {
        let x = nums[i];
        for (let d = 2; d * d <= x; d++) {
            if (x % d === 0) {
                if (!primeToIdx.has(d)) primeToIdx.set(d, []);
                primeToIdx.get(d).push(i);
                while (x % d === 0) x = Math.floor(x / d);
            }
        }
        if (x > 1) {
            if (!primeToIdx.has(x)) primeToIdx.set(x, []);
            primeToIdx.get(x).push(i);
        }
    }
    const dist = new Array(n).fill(-1);
    dist[0] = 0;
    const q = [0];
    const visitedPrimes = new Set();
    let head = 0;
    while (head < q.length) {
        const idx = q[head++];
        const d = dist[idx];
        for (const nxt of [idx - 1, idx + 1]) {
            if (nxt >= 0 && nxt < n && dist[nxt] === -1) {
                dist[nxt] = d + 1;
                if (nxt === n - 1) return dist[nxt];
                q.push(nxt);
            }
        }
        let x = nums[idx];
        const primes = [];
        for (let f = 2; f * f <= x; f++) {
            if (x % f === 0) { primes.push(f); while (x % f === 0) x = Math.floor(x / f); }
        }
        if (x > 1) primes.push(x);
        for (const p of primes) {
            if (!visitedPrimes.has(p)) {
                visitedPrimes.add(p);
                for (const nxt of (primeToIdx.get(p) || [])) {
                    if (dist[nxt] === -1) {
                        dist[nxt] = d + 1;
                        if (nxt === n - 1) return dist[nxt];
                        q.push(nxt);
                    }
                }
            }
        }
    }
    return dist[n - 1];
};

