class Solution:
    def jsonStringify(self, obj) -> str:
        if obj is None:
            return 'null'
        if isinstance(obj, bool):
            return 'true' if obj else 'false'
        if isinstance(obj, (int, float)):
            return str(obj)
        if isinstance(obj, str):
            return '"' + obj + '"'
        if isinstance(obj, list):
