var subArrayRanges = function(nums) {
    const n = nums.length;

    function sumOfExtremes(isMax) {
        let total = 0;
        const stack = [];
        for (let i = 0; i <= n; i++) {
            while (stack.length && (i === n || (isMax ? nums[stack[stack.length-1]] < nums[i] : nums[stack[stack.length-1]] > nums[i]))) {
                const mid = stack.pop();
                const left = stack.length ? stack[stack.length-1] : -1;
                total += nums[mid] * (i - mid) * (mid - left);
            }
            stack.push(i);
        }
        return total;
    }

    return sumOfExtremes(true) - sumOfExtremes(false);
};

