from typing import List
from collections import defaultdict, deque

class Solution:
    def minJumps(self, arr: List[int]) -> int:
        n = len(arr)
        if n == 1:
            return 0

        graph = defaultdict(list)
        for i, v in enumerate(arr):
            graph[v].append(i)

        visited = {0}
        queue = deque([0])
        steps = 0

        while queue:
            steps += 1
            for _ in range(len(queue)):
                i = queue.popleft()
                for nxt in [i - 1, i + 1] + graph[arr[i]]:
                    if nxt == n - 1:
                        return steps
                    if 0 <= nxt < n and nxt not in visited:
                        visited.add(nxt)
                        queue.append(nxt)
                graph[arr[i]] = []  # clear to avoid revisiting
        return -1

solution_js:
var minJumps = function(arr) {
    const n = arr.length;
    if (n === 1) return 0;

    const graph = new Map();
    for (let i = 0; i < n; i++) {
        if (!graph.has(arr[i])) graph.set(arr[i], []);
        graph.get(arr[i]).push(i);
    }

    const visited = new Set([0]);
    let queue = [0];
    let steps = 0;

    while (queue.length) {
        steps++;
        const next = [];
        for (const i of queue) {
            const neighbors = [i - 1, i + 1, ...(graph.get(arr[i]) || [])];
            graph.set(arr[i], []);  // clear to prevent re-processing
            for (const j of neighbors) {
                if (j === n - 1) return steps;
                if (j >= 0 && j < n && !visited.has(j)) {
                    visited.add(j);
                    next.push(j);
                }
            }
        }
        queue = next;
    }
    return -1;
};

