var findThePrefixCommonArray = function(A, B) {
    const n = A.length;
    const freq = new Array(n + 1).fill(0);
    let common = 0;
    const result = [];

    for (let i = 0; i < n; i++) {
        freq[A[i]]++;
        if (freq[A[i]] === 2) common++;
        freq[B[i]]++;
        if (freq[B[i]] === 2) common++;
        result.push(common);
    }

    return result;
