from typing import List

class Solution:
    def minSubarray(self, nums: List[int], p: int) -> int:
        target = sum(nums) % p
        if target == 0:
            return 0

        # Map from prefix_sum_mod_p -> most recent index
        prefix_map = {0: -1}
        cur = 0
        min_len = len(nums)

        for i, num in enumerate(nums):
            cur = (cur + num) % p
            need = (cur - target) % p
            if need in prefix_map:
                min_len = min(min_len, i - prefix_map[need])
            prefix_map[cur] = i

        return min_len if min_len < len(nums) else -1

solution_js:
var minSubarray = function(nums, p) {
    const total = nums.reduce((a, b) => a + b, 0);
    const target = Number(BigInt(total) % BigInt(p));
    if (target === 0) return 0;

    const prefixMap = new Map([[0, -1]]);
    let cur = 0;
    let minLen = nums.length;

    for (let i = 0; i < nums.length; i++) {
        cur = (cur + nums[i]) % p;
        const need = ((cur - target) % p + p) % p;
        if (prefixMap.has(need)) {
            minLen = Math.min(minLen, i - prefixMap.get(need));
        }
        prefixMap.set(cur, i);
    }

    return minLen < nums.length ? minLen : -1;
};

