class Solution:
    def removeKdigits(self, num: str, k: int) -> str:
        stack = []
        for digit in num:
            while k and stack and stack[-1] > digit:
                stack.pop()
                k -= 1
            stack.append(digit)
        # If k still > 0, remove from end
        if k:
            stack = stack[:-k]
        # Strip leading zeros
        result = ''.join(stack).lstrip('0')
        return result if result else '0'

