from typing import List

class Solution:
    def combine(self, n: int, k: int) -> List[List[int]]:
        result = []
        def backtrack(start, current):
            if len(current) == k:
                result.append(current[:])
                return
            # Pruning: need at least (k - len(current)) more numbers
            for i in range(start, n - (k - len(current)) + 2):
                current.append(i)
                backtrack(i + 1, current)
                current.pop()
        backtrack(1, [])
        return result

solution_js:
var combine = function(n, k) {
    const result = [];
    function backtrack(start, current) {
        if (current.length === k) {
            result.push([...current]);
            return;
        }
        const need = k - current.length;
        for (let i = start; i <= n - need + 1; i++) {
            current.push(i);
            backtrack(i + 1, current);
            current.pop();
        }
    }
    backtrack(1, []);
    return result;
};

var findSubstring = function(s, words) {
    if (!s || !words.length) return [];
    const wordLen = words[0].length;
    const numWords = words.length;
    const wordCount = {};
    for (const w of words) wordCount[w] = (wordCount[w] || 0) + 1;
    const result = [];

    for (let offset = 0; offset < wordLen; offset++) {
        let left = offset;
        let count = 0;
        const current = {};
        for (let right = offset; right <= s.length - wordLen; right += wordLen) {
            const word = s.slice(right, right + wordLen);
            if (word in wordCount) {
                current[word] = (current[word] || 0) + 1;
                count++;
                while (current[word] > wordCount[word]) {
                    const leftWord = s.slice(left, left + wordLen);
                    current[leftWord]--;
                    count--;
                    left += wordLen;
                }
                if (count === numWords) result.push(left);
            } else {
                for (const k in current) delete current[k];
                count = 0;
                left = right + wordLen;
            }
        }
    }
    return result;
};

