from typing import List

class Solution:
    def numIslands2(self, m: int, n: int, positions: List[List[int]]) -> List[int]:
        parent = {}
        rank = {}

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px == py:
                return False
            if rank.get(px, 0) < rank.get(py, 0):
                px, py = py, px
            parent[py] = px
            if rank.get(px, 0) == rank.get(py, 0):
                rank[px] = rank.get(px, 0) + 1
            return True

        count = 0
        result = []
        for r, c in positions:
            if (r, c) in parent:
                result.append(count)
                continue
            parent[(r, c)] = (r, c)
            count += 1
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r + dr, c + dc
                if (nr, nc) in parent:
                    if union((r, c), (nr, nc)):
                        count -= 1
            result.append(count)
        return result

solution_js:
var numIslands2 = function(m, n, positions) {
    const parent = new Map();
    const rank = new Map();

    function find(x) {
        if (parent.get(x) !== x) parent.set(x, find(parent.get(x)));
        return parent.get(x);
    }

    function union(x, y) {
        const px = find(x), py = find(y);
        if (px === py) return false;
        const rx = rank.get(px) || 0, ry = rank.get(py) || 0;
        if (rx < ry) { parent.set(px, py); }
        else if (rx > ry) { parent.set(py, px); }
        else { parent.set(py, px); rank.set(px, rx + 1); }
        return true;
    }

    let count = 0;
    const result = [];
    for (const [r, c] of positions) {
        const key = `${r},${c}`;
        if (parent.has(key)) { result.push(count); continue; }
        parent.set(key, key);
        count++;
        for (const [dr, dc] of [[-1,0],[1,0],[0,-1],[0,1]]) {
            const nk = `${r+dr},${c+dc}`;
            if (parent.has(nk) && union(key, nk)) count--;
        }
        result.push(count);
    }
    return result;
};

